import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Không tìm thấy thẻ root để mount ứng dụng");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface HoSoDat {
  id: string; // ID duy nhất để quản lý trong code
  maHS: string;
  ngayNhanHS: string;
  chuSuDung: string;
  diaChiChu: string;
  mst: string;
  cccd: string;
  soGCN: string;
  ngayCap: string;
  thua: string;
  to: string;
  diaChiThua: string;
  dienTichTong: number;
  dienTichDatO: number;
  dienTichNN: number; // Tự động tính
  ghiChu?: string;
}

export enum ViewState {
  DASHBOARD = 'DASHBOARD',
  LIST = 'LIST',
  ADD = 'ADD',
  EDIT = 'EDIT'
}

import { HoSoDat } from '../types';

const STORAGE_KEY = 'minhhung_land_records_v1';

export const getRecords = (): HoSoDat[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    console.error("Lỗi đọc dữ liệu:", error);
    return [];
  }
};

export const saveRecord = (record: HoSoDat): void => {
  const records = getRecords();
  const existingIndex = records.findIndex(r => r.id === record.id);

  if (existingIndex >= 0) {
    records[existingIndex] = record;
  } else {
    records.push(record);
  }

  localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
};

export const deleteRecord = (id: string): void => {
  const records = getRecords();
  const newRecords = records.filter(r => r.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(newRecords));
};

export const exportToCSV = (records: HoSoDat[]) => {
  // Tạo BOM cho Excel hiển thị đúng tiếng Việt
  const BOM = "\uFEFF"; 
  const headers = [
    "STT", "Mã HS", "Ngày nhận", "Chủ sử dụng", "Địa chỉ chủ", 
    "MST", "CCCD", "Số GCN", "Ngày cấp", "Thửa", "Tờ", 
    "Địa chỉ thửa", "DT Tổng", "DT Đất ở", "DT Nông nghiệp"
  ];

  const csvContent = [
    headers.join(","),
    ...records.map((r, index) => [
      index + 1,
      `"${r.maHS}"`, // Bọc ngoặc kép để tránh lỗi nếu có dấu phẩy
      `"${r.ngayNhanHS}"`,
      `"${r.chuSuDung}"`,
      `"${r.diaChiChu}"`,
      `"${r.mst}"`,
      `"${r.cccd}"`,
      `"${r.soGCN}"`,
      `"${r.ngayCap}"`,
      `"${r.thua}"`,
      `"${r.to}"`,
      `"${r.diaChiThua}"`,
      r.dienTichTong,
      r.dienTichDatO,
      r.dienTichNN
    ].join(","))
  ].join("\n");

  const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `Danh_Sach_Ho_So_Minh_Hung_${new Date().toISOString().slice(0,10)}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import React, { useState, useEffect } from 'react';
import { HoSoDat } from '../types';
import { Save, X, Calculator } from 'lucide-react';

interface Props {
  initialData?: HoSoDat;
  onSave: (data: HoSoDat) => void;
  onCancel: () => void;
}

const RecordForm: React.FC<Props> = ({ initialData, onSave, onCancel }) => {
  const [formData, setFormData] = useState<HoSoDat>(() => {
    if (initialData) return initialData;
    return {
      id: crypto.randomUUID(),
      maHS: '',
      ngayNhanHS: new Date().toISOString().slice(0, 10),
      chuSuDung: '',
      diaChiChu: '',
      mst: '',
      cccd: '',
      soGCN: '',
      ngayCap: '',
      thua: '',
      to: '',
      diaChiThua: '',
      dienTichTong: 0,
      dienTichDatO: 0,
      dienTichNN: 0,
    };
  });

  // Tự động tính diện tích nông nghiệp khi Tổng hoặc Đất ở thay đổi
  useEffect(() => {
    const dtTong = Number(formData.dienTichTong) || 0;
    const dtO = Number(formData.dienTichDatO) || 0;
    const dtNN = Math.max(0, dtTong - dtO);

    if (dtNN !== formData.dienTichNN) {
      setFormData(prev => ({ ...prev, dienTichNN: parseFloat(dtNN.toFixed(2)) }));
    }
  }, [formData.dienTichTong, formData.dienTichDatO]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md max-w-4xl mx-auto border-t-4 border-primary">
      <h2 className="text-2xl font-bold text-gray-800 mb-6 flex items-center gap-2">
        {initialData ? '✏️ Cập nhật hồ sơ' : '📝 Thêm hồ sơ mới'}
      </h2>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Phần 1: Thông tin hồ sơ & Chủ sử dụng */}
        <div className="bg-blue-50 p-4 rounded-md border border-blue-100">
          <h3 className="text-lg font-semibold text-blue-800 mb-4 border-b border-blue-200 pb-2">I. Thông tin chung</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Mã Hồ Sơ <span className="text-red-500">*</span></label>
              <input required type="text" name="maHS" value={formData.maHS} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" placeholder="VD: CMD001" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Ngày nhận HS</label>
              <input type="date" name="ngayNhanHS" value={formData.ngayNhanHS} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" />
            </div>
             <div>
              <label className="block text-sm font-medium text-gray-700">Tên Chủ sử dụng <span className="text-red-500">*</span></label>
              <input required type="text" name="chuSuDung" value={formData.chuSuDung} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary uppercase" placeholder="NGUYỄN VĂN A" />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700">Địa chỉ chủ (HKTT)</label>
              <input type="text" name="diaChiChu" value={formData.diaChiChu} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" />
            </div>
             <div>
              <label className="block text-sm font-medium text-gray-700">CCCD/CMND</label>
              <input type="text" name="cccd" value={formData.cccd} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Mã số thuế</label>
              <input type="text" name="mst" value={formData.mst} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" />
            </div>
          </div>
        </div>

        {/* Phần 2: Thông tin đất đai */}
        <div className="bg-green-50 p-4 rounded-md border border-green-100">
          <h3 className="text-lg font-semibold text-green-800 mb-4 border-b border-green-200 pb-2">II. Thông tin thửa đất</h3>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
             <div>
              <label className="block text-sm font-medium text-gray-700">Số GCN</label>
              <input type="text" name="soGCN" value={formData.soGCN} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" placeholder="CS..." />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Ngày cấp</label>
              <input type="date" name="ngayCap" value={formData.ngayCap} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Số Tờ</label>
              <input type="text" name="to" value={formData.to} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Số Thửa</label>
              <input type="text" name="thua" value={formData.thua} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" />
            </div>
             <div className="md:col-span-4">
              <label className="block text-sm font-medium text-gray-700">Địa chỉ thửa đất</label>
              <input type="text" name="diaChiThua" value={formData.diaChiThua} onChange={handleChange} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-primary focus:border-primary" placeholder="Ấp 1, Minh Hưng..." />
            </div>
          </div>
        </div>

        {/* Phần 3: Diện tích */}
        <div className="bg-orange-50 p-4 rounded-md border border-orange-100">
          <h3 className="text-lg font-semibold text-orange-800 mb-4 border-b border-orange-200 pb-2 flex items-center gap-2">
            <Calculator size={20} />
            III. Tính toán diện tích (m²)
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div>
              <label className="block text-sm font-bold text-gray-700">Diện tích TỔNG</label>
              <input 
                type="number" 
                step="0.1" 
                name="dienTichTong" 
                value={formData.dienTichTong} 
                onChange={handleChange} 
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 text-lg font-semibold text-blue-600 focus:ring-primary focus:border-primary" 
              />
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700">Diện tích ĐẤT Ở</label>
              <input 
                type="number" 
                step="0.1" 
                name="dienTichDatO" 
                value={formData.dienTichDatO} 
                onChange={handleChange} 
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 text-lg font-semibold text-green-600 focus:ring-primary focus:border-primary" 
              />
            </div>
            <div className="relative">
              <label className="block text-sm font-bold text-gray-700">Diện tích NÔNG NGHIỆP</label>
              <input 
                type="number" 
                disabled 
                value={formData.dienTichNN} 
                className="mt-1 block w-full rounded-md border-gray-300 bg-gray-100 cursor-not-allowed shadow-sm border p-2 text-lg font-bold text-orange-600" 
              />
              <span className="absolute right-2 top-8 text-xs text-gray-500 italic">(Tự động trừ)</span>
            </div>
          </div>
        </div>

        <div className="flex justify-end gap-3 pt-4">
          <button type="button" onClick={onCancel} className="flex items-center gap-2 px-4 py-2 bg-gray-200 hover:bg-gray-300 text-gray-800 rounded transition-colors">
            <X size={18} /> Hủy bỏ
          </button>
          <button type="submit" className="flex items-center gap-2 px-6 py-2 bg-primary hover:bg-blue-800 text-white font-bold rounded shadow-lg transition-transform transform hover:scale-105">
            <Save size={18} /> Lưu Hồ Sơ
          </button>
        </div>
      </form>
    </div>
  );
};

export default RecordForm;

import React, { useState, useMemo } from 'react';
import { HoSoDat } from '../types';
import { Edit, Trash2, Search, FileDown } from 'lucide-react';
import { exportToCSV } from '../services/storage';

interface Props {
  records: HoSoDat[];
  onEdit: (record: HoSoDat) => void;
  onDelete: (id: string) => void;
}

const RecordList: React.FC<Props> = ({ records, onEdit, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredRecords = useMemo(() => {
    return records.filter(r => 
      r.chuSuDung.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.maHS.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.soGCN.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.diaChiThua.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [records, searchTerm]);

  const handleDelete = (id: string, name: string) => {
    if (window.confirm(`Bạn có chắc muốn xóa hồ sơ của "${name}" không?`)) {
      onDelete(id);
    }
  };

  return (
    <div className="bg-white p-4 rounded-lg shadow min-h-[500px] flex flex-col">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <h2 className="text-xl font-bold text-gray-800">Danh sách hồ sơ ({filteredRecords.length})</h2>

        <div className="flex w-full md:w-auto gap-2">
          <div className="relative flex-grow md:flex-grow-0">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Search size={18} className="text-gray-400" />
            </div>
            <input
              type="text"
              placeholder="Tìm theo Tên, Mã HS, Số GCN..."
              className="pl-10 pr-4 py-2 border rounded-md w-full md:w-64 focus:outline-none focus:ring-2 focus:ring-primary"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <button 
            onClick={() => exportToCSV(filteredRecords)}
            className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded shadow transition-colors"
            title="Xuất file Excel (CSV)"
          >
            <FileDown size={18} /> <span className="hidden md:inline">Xuất Excel</span>
          </button>
        </div>
      </div>

      <div className="overflow-x-auto flex-grow">
        <table className="min-w-full divide-y divide-gray-200 border text-sm">
          <thead className="bg-gray-100">
            <tr>
              <th className="px-3 py-3 text-left font-bold text-gray-600 uppercase tracking-wider w-10">STT</th>
              <th className="px-3 py-3 text-left font-bold text-gray-600 uppercase tracking-wider">Mã HS</th>
              <th className="px-3 py-3 text-left font-bold text-gray-600 uppercase tracking-wider">Ngày Nhận</th>
              <th className="px-3 py-3 text-left font-bold text-gray-600 uppercase tracking-wider">Chủ Sử Dụng</th>
              <th className="px-3 py-3 text-left font-bold text-gray-600 uppercase tracking-wider hidden md:table-cell">Địa chỉ thửa</th>
              <th className="px-3 py-3 text-center font-bold text-gray-600 uppercase tracking-wider">Tờ/Thửa</th>
              <th className="px-3 py-3 text-right font-bold text-gray-600 uppercase tracking-wider">Diện Tích</th>
              <th className="px-3 py-3 text-center font-bold text-gray-600 uppercase tracking-wider w-24">Thao tác</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {filteredRecords.length > 0 ? (
              filteredRecords.map((record, index) => (
                <tr key={record.id} className="hover:bg-blue-50 transition-colors">
                  <td className="px-3 py-4 whitespace-nowrap text-gray-500">{index + 1}</td>
                  <td className="px-3 py-4 whitespace-nowrap font-medium text-primary">{record.maHS}</td>
                  <td className="px-3 py-4 whitespace-nowrap text-gray-600">{record.ngayNhanHS.split('-').reverse().join('/')}</td>
                  <td className="px-3 py-4 text-gray-800 font-medium">
                    <div>{record.chuSuDung}</div>
                    <div className="text-xs text-gray-500 md:hidden">{record.diaChiChu}</div>
                  </td>
                  <td className="px-3 py-4 text-gray-600 hidden md:table-cell max-w-xs truncate" title={record.diaChiThua}>
                    {record.diaChiThua}
                  </td>
                  <td className="px-3 py-4 whitespace-nowrap text-center text-gray-600">
                    <span className="bg-gray-100 px-2 py-1 rounded border">T:{record.to}</span>
                    <span className="mx-1">/</span>
                    <span className="bg-gray-100 px-2 py-1 rounded border">Th:{record.thua}</span>
                  </td>
                  <td className="px-3 py-4 whitespace-nowrap text-right text-gray-700">
                    <div className="font-semibold">{record.dienTichTong} m²</div>
                    <div className="text-xs text-green-600">O: {record.dienTichDatO}</div>
                    <div className="text-xs text-orange-600">NN: {record.dienTichNN}</div>
                  </td>
                  <td className="px-3 py-4 whitespace-nowrap text-center">
                    <div className="flex justify-center gap-2">
                      <button 
                        onClick={() => onEdit(record)}
                        className="p-1.5 bg-blue-100 text-blue-600 rounded hover:bg-blue-200" 
                        title="Sửa"
                      >
                        <Edit size={16} />
                      </button>
                      <button 
                        onClick={() => handleDelete(record.id, record.chuSuDung)}
                        className="p-1.5 bg-red-100 text-red-600 rounded hover:bg-red-200" 
                        title="Xóa"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={8} className="px-6 py-12 text-center text-gray-500 italic">
                  Chưa có dữ liệu. Vui lòng thêm hồ sơ mới.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default RecordList;

import React from 'react';
import { HoSoDat } from '../types';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { FileText, LandPlot, Ruler, Calendar } from 'lucide-react';

interface Props {
  records: HoSoDat[];
}

const Dashboard: React.FC<Props> = ({ records }) => {
  // Thống kê tổng quan
  const totalArea = records.reduce((sum, r) => sum + (r.dienTichTong || 0), 0);
  const totalResidential = records.reduce((sum, r) => sum + (r.dienTichDatO || 0), 0);

  // Chuẩn bị dữ liệu cho biểu đồ (5 hồ sơ có diện tích lớn nhất)
  const chartData = [...records]
    .sort((a, b) => b.dienTichTong - a.dienTichTong)
    .slice(0, 5)
    .map(r => ({
      name: r.chuSuDung.split(' ').pop(), // Lấy tên cuối
      full: r.chuSuDung,
      dt: r.dienTichTong
    }));

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {/* Card 1: Tổng hồ sơ */}
        <div className="bg-white p-6 rounded-lg shadow border-l-4 border-blue-500 flex items-center justify-between">
          <div>
            <p className="text-sm text-gray-500 uppercase font-semibold">Tổng hồ sơ</p>
            <p className="text-3xl font-bold text-gray-800 mt-1">{records.length}</p>
          </div>
          <div className="p-3 bg-blue-100 rounded-full text-blue-600">
            <FileText size={24} />
          </div>
        </div>

        {/* Card 2: Tổng diện tích */}
        <div className="bg-white p-6 rounded-lg shadow border-l-4 border-green-500 flex items-center justify-between">
          <div>
            <p className="text-sm text-gray-500 uppercase font-semibold">Tổng diện tích</p>
            <p className="text-3xl font-bold text-gray-800 mt-1">
              {totalArea.toLocaleString('vi-VN')} <span className="text-base font-normal text-gray-500">m²</span>
            </p>
          </div>
          <div className="p-3 bg-green-100 rounded-full text-green-600">
            <LandPlot size={24} />
          </div>
        </div>

        {/* Card 3: Đất ở */}
        <div className="bg-white p-6 rounded-lg shadow border-l-4 border-orange-500 flex items-center justify-between">
          <div>
            <p className="text-sm text-gray-500 uppercase font-semibold">Tổng Đất ở</p>
            <p className="text-3xl font-bold text-gray-800 mt-1">
              {totalResidential.toLocaleString('vi-VN')} <span className="text-base font-normal text-gray-500">m²</span>
            </p>
          </div>
          <div className="p-3 bg-orange-100 rounded-full text-orange-600">
            <Ruler size={24} />
          </div>
        </div>

        {/* Card 4: Tháng hiện tại */}
        <div className="bg-white p-6 rounded-lg shadow border-l-4 border-purple-500 flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-500 uppercase font-semibold">Tháng {new Date().getMonth() + 1}</p>
              <p className="text-xl font-bold text-gray-800 mt-1">Đang xử lý</p>
            </div>
            <div className="p-3 bg-purple-100 rounded-full text-purple-600">
              <Calendar size={24} />
            </div>
        </div>
      </div>

      {/* Biểu đồ */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
         <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-bold text-gray-800 mb-4">Top 5 Thửa đất diện tích lớn nhất</h3>
            <div className="h-64">
              {records.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <XAxis dataKey="name" />
                    <YAxis />
                    <Tooltip 
                      formatter={(value: number) => [`${value} m²`, 'Diện tích']}
                      labelFormatter={(label, payload) => {
                         if (payload && payload.length > 0) return payload[0].payload.full;
                         return label;
                      }}
                    />
                    <Bar dataKey="dt" fill="#0f4c81" radius={[4, 4, 0, 0]}>
                       {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#0f4c81' : '#f39c12'} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-gray-400 italic">Chưa có dữ liệu biểu đồ</div>
              )}
            </div>
         </div>

         <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-bold text-gray-800 mb-4">Ghi chú nhanh</h3>
            <div className="bg-yellow-50 p-4 rounded border border-yellow-200 h-64 overflow-y-auto text-sm text-gray-700">
              <ul className="list-disc pl-5 space-y-2">
                <li>Kiểm tra kỹ <strong>Mã Hồ Sơ</strong> để tránh trùng lặp.</li>
                <li>Diện tích <strong>Nông nghiệp</strong> được tính tự động = Tổng - Đất ở.</li>
