import React, { useState, useEffect } from 'react';
import { HoSoDat } from '../types';
import { Save, X, User, MapPin, FileText, CheckCircle2 } from 'lucide-react';

interface Props {
  initialData?: HoSoDat;
  onSave: (data: HoSoDat) => void;
  onCancel: () => void;
}

const RecordForm: React.FC<Props> = ({ initialData, onSave, onCancel }) => {
  const [formData, setFormData] = useState<HoSoDat>(() => {
    if (initialData) return initialData;
    return {
      id: crypto.randomUUID(),
      maHS: '',
      ngayNhanHS: new Date().toISOString().slice(0, 10),
      chuSuDung: '',
      diaChiChu: '',
      mst: '',
      cccd: '',
      soGCN: '',
      ngayCap: '',
      thua: '',
      to: '',
      diaChiThua: '',
      dienTichTong: 0,
      dienTichDatO: 0,
      dienTichNN: 0,
    };
  });

  useEffect(() => {
    const dtTong = Number(formData.dienTichTong) || 0;
    const dtO = Number(formData.dienTichDatO) || 0;
    const dtNN = Math.max(0, dtTong - dtO);

    if (dtNN !== formData.dienTichNN) {
      setFormData(prev => ({ ...prev, dienTichNN: parseFloat(dtNN.toFixed(2)) }));
    }
  }, [formData.dienTichTong, formData.dienTichDatO]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  // Components nhỏ để tái sử dụng style
  const SectionHeader = ({ icon: Icon, title }: { icon: any, title: string }) => (
    <div className="flex items-center gap-2 mb-4 pb-2 border-b border-gray-200">
      <div className="p-1.5 bg-blue-50 text-gov-primary rounded">
        <Icon size={18} />
      </div>
      <h3 className="font-bold text-gray-800 uppercase text-sm tracking-wide">{title}</h3>
    </div>
  );

  const InputGroup = ({ label, required = false, children }: any) => (
    <div className="mb-1">
      <label className="block text-xs font-semibold text-gray-600 mb-1.5 uppercase">
        {label} {required && <span className="text-red-600">*</span>}
      </label>
      {children}
    </div>
  );

  const inputClass = "block w-full rounded border-gray-300 shadow-sm border px-3 py-2 text-sm focus:ring-1 focus:ring-gov-primary focus:border-gov-primary transition-colors placeholder-gray-400";

  return (
    <div className="max-w-5xl mx-auto">
      <div className="bg-white rounded shadow-md border border-gray-200 overflow-hidden">
        {/* Form Header */}
        <div className="bg-gov-primary text-white px-6 py-4 flex justify-between items-center">
          <div>
            <h2 className="text-lg font-bold uppercase tracking-wider">
              {initialData ? 'Cập nhật thông tin hồ sơ' : 'Tiếp nhận hồ sơ mới'}
            </h2>
            <p className="text-xs text-blue-200 opacity-80 mt-1">Vui lòng nhập đầy đủ thông tin vào các trường bắt buộc (*)</p>
          </div>
          <div className="bg-white/10 p-2 rounded-full">
            <FileText size={24} />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 bg-gray-50/50">
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

            {/* Cột trái: Thông tin chính */}
            <div className="lg:col-span-8 space-y-6">

              {/* Box 1: Thông tin chủ sở hữu */}
              <div className="bg-white p-5 rounded border border-gray-200 shadow-sm">
                <SectionHeader icon={User} title="I. Thông tin Chủ sử dụng" />
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="md:col-span-2">
                    <InputGroup label="Họ và tên chủ sử dụng" required>
                      <input required type="text" name="chuSuDung" value={formData.chuSuDung} onChange={handleChange} className={`${inputClass} uppercase font-medium text-gov-primary`} placeholder="NGUYỄN VĂN A..." />
                    </InputGroup>
                  </div>
                  <div>
                    <InputGroup label="Số CCCD / CMND">
                      <input type="text" name="cccd" value={formData.cccd} onChange={handleChange} className={inputClass} placeholder="070..." />
                    </InputGroup>
                  </div>
                  <div>
                    <InputGroup label="Mã số thuế">
                      <input type="text" name="mst" value={formData.mst} onChange={handleChange} className={inputClass} placeholder="Mã số thuế cá nhân..." />
                    </InputGroup>
                  </div>
                  <div className="md:col-span-2">
                    <InputGroup label="Địa chỉ thường trú (HKTT)">
                      <input type="text" name="diaChiChu" value={formData.diaChiChu} onChange={handleChange} className={inputClass} placeholder="Số nhà, đường, ấp..." />
                    </InputGroup>
                  </div>
                </div>
              </div>

              {/* Box 2: Thông tin thửa đất */}
              <div className="bg-white p-5 rounded border border-gray-200 shadow-sm">
