      diaChiChu: '',
      mst: '',
      cccd: '',
      soGCN: '',
      ngayCap: '',
      thua: '',
      to: '',
      diaChiThua: '',
      dienTichTong: '', // Để chuỗi rỗng để placeholder hiển thị hoặc người dùng dễ nhập
      dienTichDatO: '',
      dienTichNN: 0,
    };
  });

  // Tự động tính diện tích nông nghiệp
  useEffect(() => {
    // Chuyển đổi sang số để tính toán, chấp nhận chuỗi rỗng là 0
    const valTong = formData.dienTichTong === '' ? 0 : parseFloat(formData.dienTichTong);
    const valDatO = formData.dienTichDatO === '' ? 0 : parseFloat(formData.dienTichDatO);

    const dtTong = isNaN(valTong) ? 0 : valTong;
