export default RecordForm;

import { HoSoDat } from '../types';

const STORAGE_KEY = 'minhhung_land_records_v1';

export const getRecords = (): HoSoDat[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    console.error("Lỗi đọc dữ liệu:", error);
    return [];
  }
};

export const saveRecord = (record: HoSoDat): void => {
  const records = getRecords();
  const existingIndex = records.findIndex(r => r.id === record.id);

  if (existingIndex >= 0) {
    records[existingIndex] = record;
  } else {
    records.push(record);
  }

  localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
};

// Hàm mới: Lưu nhiều hồ sơ cùng lúc (dùng cho Import Excel)
export const importRecords = (newRecords: HoSoDat[]): void => {
  const currentRecords = getRecords();
  // Nối danh sách mới vào danh sách cũ
  const updatedRecords = [...currentRecords, ...newRecords];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedRecords));
};

export const deleteRecord = (id: string): void => {
  const records = getRecords();
  const newRecords = records.filter(r => r.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(newRecords));
};

export const exportToCSV = (records: HoSoDat[]) => {
  // Tạo BOM cho Excel hiển thị đúng tiếng Việt
  const BOM = "\uFEFF"; 
  const headers = [
    "STT", "Mã HS", "Ngày nhận", "Chủ sử dụng", "Địa chỉ chủ", 
    "MST", "CCCD", "Số GCN", "Ngày cấp", "Thửa", "Tờ", 
    "Địa chỉ thửa", "DT Tổng", "DT Đất ở", "DT Nông nghiệp"
  ];

  const csvContent = [
    headers.join(","),
    ...records.map((r, index) => [
      index + 1,
      `"${r.maHS}"`, // Bọc ngoặc kép để tránh lỗi nếu có dấu phẩy
      `"${r.ngayNhanHS}"`,
      `"${r.chuSuDung}"`,
      `"${r.diaChiChu}"`,
      `"${r.mst}"`,
      `"${r.cccd}"`,
      `"${r.soGCN}"`,
      `"${r.ngayCap}"`,
      `"${r.thua}"`,
      `"${r.to}"`,
      `"${r.diaChiThua}"`,
      r.dienTichTong,
      r.dienTichDatO,
      r.dienTichNN
    ].join(","))
  ].join("\n");

  const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `Danh_Sach_Ho_So_Minh_Hung_${new Date().toISOString().slice(0,10)}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

