import React, { useState, useMemo, useRef } from 'react';
import { HoSoDat } from '../types';
import { Edit, Trash2, Search, FileDown, Upload, Filter } from 'lucide-react';
import { exportToCSV } from '../services/storage';
// @ts-ignore
import { read, utils } from 'xlsx';

interface Props {
  records: HoSoDat[];
  onEdit: (record: HoSoDat) => void;
  onDelete: (id: string) => void;
  onImport: (records: HoSoDat[]) => void;
}

const RecordList: React.FC<Props> = ({ records, onEdit, onDelete, onImport }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filteredRecords = useMemo(() => {
    return records.filter(r => 
      r.chuSuDung.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.maHS.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.soGCN.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.diaChiThua.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [records, searchTerm]);

  const handleDelete = (id: string, name: string) => {
    if (window.confirm(`XÁC NHẬN XÓA HỒ SƠ?\n\nChủ sử dụng: ${name}\n\nHành động này không thể hoàn tác.`)) {
      onDelete(id);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        // Đọc dữ liệu thô từ Excel
        const data = utils.sheet_to_json(ws);

        // Map dữ liệu từ cột Excel (Tiếng Việt) sang Interface (Tiếng Anh)
        const mappedData: HoSoDat[] = data.map((row: any) => {
          const dtTong = Number(row['DT Tổng']) || 0;
          const dtO = Number(row['DT Đất ở']) || 0;

          return {
            id: crypto.randomUUID(),
            maHS: row['Mã HS']?.toString() || '',
            ngayNhanHS: row['Ngày nhận'] || new Date().toISOString().slice(0, 10),
            chuSuDung: row['Chủ sử dụng'] || 'Chưa xác định',
            diaChiChu: row['Địa chỉ chủ'] || '',
            mst: row['MST']?.toString() || '',
            cccd: row['CCCD']?.toString() || '',
            soGCN: row['Số GCN']?.toString() || '',
            ngayCap: row['Ngày cấp'] || '',
            thua: row['Thửa']?.toString() || '',
            to: row['Tờ']?.toString() || '',
            diaChiThua: row['Địa chỉ thửa'] || '',
            dienTichTong: dtTong,
            dienTichDatO: dtO,
            dienTichNN: Math.max(0, parseFloat((dtTong - dtO).toFixed(2))), // Tính lại NN để đảm bảo chính xác
            ghiChu: ''
          };
        }).filter((r: HoSoDat) => r.maHS !== '' && r.chuSuDung !== 'Chưa xác định'); // Lọc bỏ dòng trống

        if (mappedData.length > 0) {
          onImport(mappedData);
        } else {
          alert('Không tìm thấy dữ liệu hợp lệ trong file Excel.\nVui lòng kiểm tra lại tên cột.');
        }

      } catch (error) {
        console.error("Import lỗi:", error);
        alert('Có lỗi xảy ra khi đọc file. Vui lòng thử lại.');
      }

      // Reset input để có thể chọn lại file cũ
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsBinaryString(file);
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="flex flex-col h-full space-y-4">
      {/* Hidden File Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        accept=".xlsx, .xls, .csv" 
        className="hidden" 
      />

      {/* Toolbar */}
      <div className="bg-white p-4 rounded shadow-sm border border-gray-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2">
           <div className="bg-gov-primary text-white p-2 rounded">
             <Filter size={18}/>
           </div>
           <h3 className="font-bold text-gray-700 uppercase text-sm">Bộ lọc dữ liệu</h3>
        </div>

        <div className="flex w-full md:w-auto gap-3">
          <div className="relative flex-grow md:flex-grow-0 group">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Search size={16} className="text-gray-400 group-focus-within:text-gov-primary transition-colors" />
            </div>
            <input
              type="text"
              placeholder="Nhập Mã HS, Tên, Số GCN..."
              className="pl-9 pr-4 py-2 border border-gray-300 rounded text-sm w-full md:w-80 focus:outline-none focus:ring-1 focus:ring-gov-primary focus:border-gov-primary transition-all bg-white text-gray-900"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <button 
            onClick={triggerFileUpload}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded text-sm font-medium shadow-sm transition-colors border border-blue-700"
            title="Nhập dữ liệu từ Excel"
          >
            <Upload size={16} /> <span className="hidden md:inline">Nhập Excel</span>
          </button>

          <button 
            onClick={() => exportToCSV(filteredRecords)}
            className="flex items-center gap-2 bg-green-700 hover:bg-green-800 text-white px-4 py-2 rounded text-sm font-medium shadow-sm transition-colors border border-green-800"
            title="Xuất dữ liệu ra Excel"
          >
            <FileDown size={16} /> <span className="hidden md:inline">Xuất Excel</span>
          </button>
        </div>
      </div>

      {/* Table Container */}
      <div className="bg-white rounded shadow-sm border border-gray-200 overflow-hidden flex-grow flex flex-col">
        <div className="overflow-x-auto flex-grow">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-100 text-gray-700">
              <tr>
                <th className="sticky top-0 bg-gray-100 px-4 py-3 text-center text-xs font-bold uppercase tracking-wider border-b border-gray-300 w-12">STT</th>
                <th className="sticky top-0 bg-gray-100 px-4 py-3 text-left text-xs font-bold uppercase tracking-wider border-b border-gray-300">Mã Hồ Sơ</th>
                <th className="sticky top-0 bg-gray-100 px-4 py-3 text-left text-xs font-bold uppercase tracking-wider border-b border-gray-300">Thông tin chủ sử dụng</th>
                <th className="sticky top-0 bg-gray-100 px-4 py-3 text-left text-xs font-bold uppercase tracking-wider border-b border-gray-300 hidden lg:table-cell">Địa chỉ đất</th>
                <th className="sticky top-0 bg-gray-100 px-4 py-3 text-center text-xs font-bold uppercase tracking-wider border-b border-gray-300">Tờ / Thửa</th>
                <th className="sticky top-0 bg-gray-100 px-4 py-3 text-right text-xs font-bold uppercase tracking-wider border-b border-gray-300">Diện tích (m²)</th>
                <th className="sticky top-0 bg-gray-100 px-4 py-3 text-center text-xs font-bold uppercase tracking-wider border-b border-gray-300 w-28">Tác vụ</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredRecords.length > 0 ? (
                filteredRecords.map((record, index) => (
                  <tr key={record.id} className="hover:bg-blue-50 transition-colors group">
                    <td className="px-4 py-3 whitespace-nowrap text-center text-sm text-gray-500 bg-gray-50/50">{index + 1}</td>

                    <td className="px-4 py-3 whitespace-nowrap">
                      <div className="text-sm font-bold text-gov-primary">{record.maHS}</div>
                      <div className="text-xs text-gray-500 mt-0.5">{record.ngayNhanHS.split('-').reverse().join('/')}</div>
                    </td>

                    <td className="px-4 py-3">
                      <div className="text-sm font-semibold text-gray-800 uppercase">{record.chuSuDung}</div>
                      <div className="text-xs text-gray-500 mt-1 flex flex-col xl:flex-row gap-1 xl:gap-3">
                        {record.cccd && <span>ID: {record.cccd}</span>}
                        {record.mst && <span className="hidden xl:inline">| MST: {record.mst}</span>}
                      </div>
                    </td>

                    <td className="px-4 py-3 hidden lg:table-cell">
                      <div className="text-sm text-gray-600 truncate max-w-xs" title={record.diaChiThua}>
                        {record.diaChiThua}
                      </div>
                      <div className="text-xs text-gray-400 mt-0.5">GCN: {record.soGCN || '---'}</div>
                    </td>

                    <td className="px-4 py-3 whitespace-nowrap text-center">
                       <div className="inline-flex gap-1">
                          <span className="px-2 py-0.5 bg-gray-100 border border-gray-300 rounded text-xs font-medium text-gray-600">T:{record.to}</span>
                          <span className="px-2 py-0.5 bg-gray-100 border border-gray-300 rounded text-xs font-medium text-gray-600">Th:{record.thua}</span>
                       </div>
                    </td>

                    <td className="px-4 py-3 whitespace-nowrap text-right">
                      <div className="text-sm font-bold text-gray-800">{record.dienTichTong.toLocaleString('vi-VN')}</div>
                      <div className="text-[10px] text-gray-500 mt-1 space-x-2">
                        <span className="text-green-700 bg-green-50 px-1 rounded">O: {record.dienTichDatO}</span>
                        <span className="text-orange-700 bg-orange-50 px-1 rounded">NN: {record.dienTichNN}</span>
                      </div>
                    </td>

                    <td className="px-4 py-3 whitespace-nowrap text-center">
                      <div className="flex justify-center gap-2 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
