                         <div className="w-px h-5 bg-gray-300 mx-1 self-center"></div>

                        <button 
                          onClick={() => onEdit(record)}
                          className="p-1.5 bg-blue-100 text-blue-800 border border-blue-300 rounded hover:bg-blue-200 transition-colors shadow-sm" 
                          title="Chỉnh sửa hồ sơ"
                        >
