                         {/* Nút Xuất Quyết Định */}
                        <button 
                          onClick={() => handleExportQuyetDinh(record)}
                          className="p-1.5 bg-purple-100 text-purple-800 border border-purple-300 rounded hover:bg-purple-200 transition-colors shadow-sm" 
                          title="Xuất Quyết định (Word)"
                        >
                          <ScrollText size={14} />
                        </button>

                         {/* Dải phân cách */}
                         <div className="w-px h-5 bg-gray-300 mx-1 self-center"></div>

                        <button 
                          onClick={() => onEdit(record)}
                          className="p-1.5 bg-blue-100 text-blue-800 border border-blue-300 rounded hover:bg-blue-200 transition-colors shadow-sm" 
                          title="Chỉnh sửa hồ sơ"
                        >
                          <Edit size={14} />
                        </button>
                        <button 
                          onClick={() => handleDelete(record.id, record.chuSuDung)}
                          className="p-1.5 bg-red-100 text-red-800 border border-red-300 rounded hover:bg-red-200 transition-colors shadow-sm" 
                          title="Xóa hồ sơ"
                        >
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={7} className="px-6 py-16 text-center">
                    <div className="flex flex-col items-center justify-center text-gray-400">
                      <Search size={48} className="mb-4 opacity-20" />
                      <p className="text-lg font-medium text-gray-500">Không tìm thấy dữ liệu</p>
                      <p className="text-sm">Vui lòng thử từ khóa khác hoặc thêm mới hồ sơ.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Footer của bảng */}
        <div className="bg-gray-50 border-t border-gray-200 px-4 py-3 flex items-center justify-between">
           <span className="text-xs text-gray-500">Hiển thị {filteredRecords.length} hồ sơ</span>
