import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { getUsers, saveUser, deleteUser } from '../services/storage';
import { Trash2, UserPlus, Save, X, Shield, ShieldAlert, Check } from 'lucide-react';

const UserManagement: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [isEditing, setIsEditing] = useState(false);
  const [currentUser, setCurrentUser] = useState<Partial<User>>({});

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    const data = await getUsers();
    setUsers(data);
  };

  const handleCreate = () => {
    setCurrentUser({
      role: 'USER',
      username: '',
      password: '',
      fullName: ''
    });
    setIsEditing(true);
  };

  const handleDelete = async (id: string, username: string) => {
    if (username === 'admin') {
      alert("Không thể xóa tài khoản Admin mặc định!");
      return;
    }
    if (window.confirm(`Xóa tài khoản ${username}?`)) {
      await deleteUser(id);
      loadUsers();
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser.username || !currentUser.password || !currentUser.fullName) return;

    await saveUser(currentUser as User);
    setIsEditing(false);
    loadUsers();
  };

  return (
    <div className="space-y-6 fade-in">
      <div className="flex justify-between items-center bg-white p-4 rounded shadow-sm border border-gray-200">
        <div>
           <h3 className="font-bold text-gray-800 uppercase text-sm">Quản lý người dùng</h3>
           <p className="text-xs text-gray-500">Cấp quyền truy cập hệ thống</p>
        </div>
        <button 
          onClick={handleCreate}
          className="flex items-center gap-2 bg-gov-primary text-white px-4 py-2 rounded text-sm font-medium hover:bg-blue-800 transition-colors"
        >
          <UserPlus size={16} /> Thêm tài khoản
        </button>
      </div>

      {isEditing && (
         <div className="bg-blue-50 p-6 rounded border border-blue-200 shadow-sm animate-fade-in-down">
           <h4 className="font-bold text-blue-900 mb-4 flex items-center gap-2">
             <UserPlus size={18}/> {currentUser.id ? 'Cập nhật tài khoản' : 'Tạo tài khoản mới'}
           </h4>
           <form onSubmit={handleSave} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-gray-600 mb-1">Tên đăng nhập *</label>
                <input required type="text" className="w-full border rounded px-3 py-2 text-sm" 
                  value={currentUser.username} 
                  onChange={e => setCurrentUser({...currentUser, username: e.target.value})}
                  disabled={!!currentUser.id} // Không sửa username khi edit
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-600 mb-1">Họ và tên cán bộ *</label>
                <input required type="text" className="w-full border rounded px-3 py-2 text-sm" 
                  value={currentUser.fullName} 
                  onChange={e => setCurrentUser({...currentUser, fullName: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-600 mb-1">Mật khẩu *</label>
                <input required type="text" className="w-full border rounded px-3 py-2 text-sm font-mono" 
                  value={currentUser.password} 
                  onChange={e => setCurrentUser({...currentUser, password: e.target.value})}
                  placeholder="Nhập mật khẩu..."
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-600 mb-1">Phân quyền</label>
                <select className="w-full border rounded px-3 py-2 text-sm"
                  value={currentUser.role}
                  onChange={e => setCurrentUser({...currentUser, role: e.target.value as any})}
                >
                  <option value="USER">USER (Cán bộ - Chỉ nhập liệu)</option>
                  <option value="ADMIN">ADMIN (Quản trị viên - Toàn quyền)</option>
                </select>
              </div>

              <div className="md:col-span-2 flex justify-end gap-2 mt-2">
                 <button type="button" onClick={() => setIsEditing(false)} className="px-4 py-2 bg-white border border-gray-300 rounded text-gray-700 text-sm hover:bg-gray-50">Hủy</button>
                 <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 flex items-center gap-2">
                   <Save size={16} /> Lưu thông tin
                 </button>
              </div>
           </form>
         </div>
      )}

      <div className="bg-white rounded shadow-sm border border-gray-200 overflow-hidden">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-100">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase">Tài khoản</th>
              <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase">Họ và tên</th>
              <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase">Vai trò</th>
              <th className="px-6 py-3 text-center text-xs font-bold text-gray-500 uppercase">Mật khẩu</th>
              <th className="px-6 py-3 text-right text-xs font-bold text-gray-500 uppercase">Tác vụ</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {users.map((user) => (
              <tr key={user.id} className="hover:bg-gray-50">
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{user.username}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-700">{user.fullName}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm">
                  {user.role === 'ADMIN' ? (
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">
                      <ShieldAlert size={12} className="mr-1"/> ADMIN
                    </span>
                  ) : (
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                      <Shield size={12} className="mr-1"/> USER
                    </span>
                  )}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-center text-sm font-mono text-gray-400">******</td>
                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                  <button 
                    onClick={() => { setCurrentUser(user); setIsEditing(true); }}
                    className="text-blue-600 hover:text-blue-900 mr-4"
                  >
                    Sửa
                  </button>
                  <button 
                    onClick={() => handleDelete(user.id, user.username)}
                    className="text-red-600 hover:text-red-900 disabled:opacity-30"
                    disabled={user.username === 'admin'}
                  >
                    Xóa
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default UserManagement;

import React, { useState, useMemo, useRef } from 'react';
import { HoSoDat, UserRole } from '../types';
import { Edit, Trash2, Search, FileDown, Upload, Filter, FileText, ScrollText } from 'lucide-react';
import { exportToCSV } from '../services/storage';
// @ts-ignore
import * as XLSX from 'xlsx';

interface Props {
  records: HoSoDat[];
  onEdit: (record: HoSoDat) => void;
  onDelete: (id: string) => void;
  onImport: (records: HoSoDat[]) => void;
  userRole?: UserRole; // Thêm prop role
}

const RecordList: React.FC<Props> = ({ records, onEdit, onDelete, onImport, userRole = 'USER' }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isAdmin = userRole === 'ADMIN';

  const filteredRecords = useMemo(() => {
    return records.filter(r => 
      r.chuSuDung.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.maHS.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.soGCN.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.diaChiThua.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [records, searchTerm]);

  const handleDelete = (id: string, name: string) => {
    if (window.confirm(`XÁC NHẬN XÓA HỒ SƠ?\n\nChủ sử dụng: ${name}\n\nHành động này không thể hoàn tác.`)) {
      onDelete(id);
    }
  };

  // Hàm tạo nội dung file Word (HTML giả lập)
  const exportToDoc = (filename: string, content: string) => {
    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>Export HTML to Word Document with JavaScript</title><style>body {font-family: 'Times New Roman', serif; font-size: 14pt;} p {margin: 0; padding: 0;} .center {text-align: center; font-weight: bold;} .bold {font-weight: bold;} .italic {font-style: italic;} .underline {text-decoration: underline;}</style></head><body>";
    const footer = "</body></html>";
    const sourceHTML = header + content + footer;

    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = `${filename}.doc`;
    fileDownload.click();
    document.body.removeChild(fileDownload);
  }

  const handleExportToTrinh = (r: HoSoDat) => {
    const content = `
      <div class='center'>
        <p>CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM</p>
        <p class='underline'>Độc lập - Tự do - Hạnh phúc</p>
        <br/>
        <p>TỜ TRÌNH</p>
        <p>Về việc đề nghị chuyển mục đích sử dụng đất</p>
      </div>
      <br/>
      <p>Kính gửi: UBND Thị xã Chơn Thành</p>
      <br/>
      <p>UBND Phường Minh Hưng tiếp nhận hồ sơ của ông/bà: <span class='bold'>${r.chuSuDung.toUpperCase()}</span></p>
      <p>Địa chỉ thường trú: ${r.diaChiChu}</p>
      <p>Căn cước công dân số: ${r.cccd}</p>
      <br/>
      <p>Đang sử dụng thửa đất số: <span class='bold'>${r.thua}</span>, Tờ bản đồ số: <span class='bold'>${r.to}</span></p>
      <p>Tại địa chỉ: ${r.diaChiThua}</p>
      <p>Giấy chứng nhận QSDĐ số: ${r.soGCN}, Cấp ngày: ${r.ngayCap}</p>
      <br/>
      <p>Tổng diện tích: ${r.dienTichTong} m2. Trong đó:</p>
      <p>- Diện tích đất ở hiện có: ${r.dienTichDatO} m2</p>
      <p>- Diện tích đất nông nghiệp: ${r.dienTichNN} m2</p>
      <br/>
      <p>Nay đề nghị xin chuyển mục đích sử dụng đất đối với thửa đất trên.</p>
      <p>Kính trình UBND thị xã xem xét giải quyết./.</p>
      <br/><br/>
      <div style='text-align: right'>
        <p class='italic'>Minh Hưng, ngày .... tháng .... năm 20...</p>
        <p class='bold'>CHỦ TỊCH</p>
        <br/><br/><br/>
        <p>(Đã ký)</p>
      </div>
    `;
    exportToDoc(`ToTrinh_${r.chuSuDung}`, content);
  };

  const handleExportQuyetDinh = (r: HoSoDat) => {
    const content = `
      <div class='center'>
        <p>ỦY BAN NHÂN DÂN</p>
        <p class='underline bold'>PHƯỜNG MINH HƯNG</p>
        <br/>
        <p>QUYẾT ĐỊNH</p>
        <p>Về việc xác nhận hồ sơ chuyển mục đích sử dụng đất</p>
      </div>
      <br/>
      <p>- Căn cứ Luật Đất đai năm 2013;</p>
      <p>- Căn cứ đơn xin chuyển mục đích sử dụng đất của ông/bà: <span class='bold'>${r.chuSuDung.toUpperCase()}</span></p>
      <br/>
      <div class='center'><p>QUYẾT ĐỊNH:</p></div>
      <br/>
      <p><span class='bold'>Điều 1.</span> Thống nhất đề nghị cho phép ông/bà ${r.chuSuDung} chuyển mục đích sử dụng đất tại thửa đất số ${r.thua}, tờ bản đồ số ${r.to}.</p>
      <p>Địa chỉ thửa đất: ${r.diaChiThua}</p>
      <p>Diện tích xin chuyển mục đích: ............... m2</p>
      <br/>
      <p><span class='bold'>Điều 2.</span> Công chức Địa chính - Xây dựng có trách nhiệm hướng dẫn công dân thực hiện nghĩa vụ tài chính theo quy định.</p>
      <br/>
      <p><span class='bold'>Điều 3.</span> Quyết định này có hiệu lực kể từ ngày ký./.</p>
      <br/><br/>
      <div style='text-align: right'>
        <p class='italic'>Minh Hưng, ngày .... tháng .... năm 20...</p>
        <p class='bold'>CHỦ TỊCH</p>
        <br/><br/><br/>
        <p>(Đã ký)</p>
      </div>
    `;
    exportToDoc(`QuyetDinh_${r.chuSuDung}`, content);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        // Đọc dữ liệu thô từ Excel
        const data = XLSX.utils.sheet_to_json(ws);

        // Map dữ liệu từ cột Excel (Tiếng Việt) sang Interface (Tiếng Anh)
        const mappedData: HoSoDat[] = data.map((row: any) => {
          const dtTong = Number(row['DT Tổng']) || 0;
          const dtO = Number(row['DT Đất ở']) || 0;

          return {
            id: crypto.randomUUID(),
            maHS: row['Mã HS']?.toString() || '',
            ngayNhanHS: row['Ngày nhận'] || new Date().toISOString().slice(0, 10),
            chuSuDung: row['Chủ sử dụng'] || 'Chưa xác định',
            diaChiChu: row['Địa chỉ chủ'] || '',
            mst: row['MST']?.toString() || '',
            cccd: row['CCCD']?.toString() || '',
            soGCN: row['Số GCN']?.toString() || '',
            ngayCap: row['Ngày cấp'] || '',
            thua: row['Thửa']?.toString() || '',
            to: row['Tờ']?.toString() || '',
            diaChiThua: row['Địa chỉ thửa'] || '',
            dienTichTong: dtTong,
            dienTichDatO: dtO,
            dienTichNN: Math.max(0, parseFloat((dtTong - dtO).toFixed(2))), // Tính lại NN để đảm bảo chính xác
            ghiChu: ''
          };
        }).filter((r: HoSoDat) => r.maHS !== '' && r.chuSuDung !== 'Chưa xác định'); // Lọc bỏ dòng trống

        if (mappedData.length > 0) {
          onImport(mappedData);
        } else {
          alert('Không tìm thấy dữ liệu hợp lệ trong file Excel.\nVui lòng kiểm tra lại tên cột.');
        }

      } catch (error) {
        console.error("Import lỗi:", error);
        alert('Có lỗi xảy ra khi đọc file. Vui lòng thử lại.');
      }

      // Reset input để có thể chọn lại file cũ
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsBinaryString(file);
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="flex flex-col h-full space-y-4">
      {/* Hidden File Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        accept=".xlsx, .xls, .csv" 
        className="hidden" 
      />

      {/* Toolbar */}
      <div className="bg-white p-4 rounded shadow-sm border border-gray-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2">
           <div className="bg-gov-primary text-white p-2 rounded">
             <Filter size={18}/>
           </div>
           <h3 className="font-bold text-gray-700 uppercase text-sm">Bộ lọc dữ liệu</h3>
        </div>

        <div className="flex w-full md:w-auto gap-3">
          <div className="relative flex-grow md:flex-grow-0 group">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Search size={16} className="text-gray-400 group-focus-within:text-gov-primary transition-colors" />
            </div>
            <input
              type="text"
              placeholder="Nhập Mã HS, Tên, Số GCN..."
              className="pl-9 pr-4 py-2 border border-gray-300 rounded text-sm w-full md:w-80 focus:outline-none focus:ring-1 focus:ring-gov-primary focus:border-gov-primary transition-all bg-white text-gray-900"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          {/* Chỉ Admin mới thấy nút Import */}
          {isAdmin && (
            <button 
              onClick={triggerFileUpload}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded text-sm font-medium shadow-sm transition-colors border border-blue-700"
              title="Nhập dữ liệu từ Excel (Chỉ Admin)"
            >
              <Upload size={16} /> <span className="hidden md:inline">Nhập Excel</span>
            </button>
          )}

          <button 
            onClick={() => exportToCSV(filteredRecords)}
            className="flex items-center gap-2 bg-green-700 hover:bg-green-800 text-white px-4 py-2 rounded text-sm font-medium shadow-sm transition-colors border border-green-800"
            title="Xuất dữ liệu ra Excel"
          >
            <FileDown size={16} /> <span className="hidden md:inline">Xuất Excel</span>
          </button>
        </div>
      </div>

      {/* Table Container */}
      <div className="bg-white rounded shadow-sm border border-gray-200 overflow-hidden flex-grow flex flex-col">
        <div className="overflow-x-auto flex-grow">
