import React, { useState, useEffect } from 'react';
import { HoSoDat, ViewState, User } from './types';
import { getRecords, saveRecord, deleteRecord, importRecords } from './services/storage';
import RecordForm from './components/RecordForm';
import RecordList from './components/RecordList';
import Dashboard from './components/Dashboard';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import { LayoutDashboard, PlusCircle, List, UserCircle, Building2, ChevronRight, LogOut, Loader2, Users } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>(ViewState.LOGIN);
  const [records, setRecords] = useState<HoSoDat[]>([]);
  const [editingRecord, setEditingRecord] = useState<HoSoDat | undefined>(undefined);
  const [isLoading, setIsLoading] = useState<boolean>(false);

  // Khôi phục session từ localStorage (giả lập)
  useEffect(() => {
    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
      setView(ViewState.DASHBOARD);
    }
  }, []);

  // Hàm tải dữ liệu từ Supabase
  const loadData = async () => {
    setIsLoading(true);
    const data = await getRecords();
    setRecords(data);
    setIsLoading(false);
  };

  useEffect(() => {
    if (currentUser) {
      loadData();
    }
  }, [currentUser]);

  const handleLoginSuccess = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('currentUser', JSON.stringify(user));
    setView(ViewState.DASHBOARD);
  };

  const handleLogout = () => {
    if(window.confirm('Bạn có chắc muốn đăng xuất?')) {
      setCurrentUser(null);
      localStorage.removeItem('currentUser');
      setView(ViewState.LOGIN);
    }
  };

  const handleSave = async (record: HoSoDat) => {
    setIsLoading(true);
    const success = await saveRecord(record);
    if (success) {
      await loadData();
      setView(ViewState.LIST);
      setEditingRecord(undefined);
    }
    setIsLoading(false);
  };

  const handleImportRecords = async (newRecords: HoSoDat[]) => {
    setIsLoading(true);
    const success = await importRecords(newRecords);
    if (success) {
      await loadData();
      alert(`Đã nhập thành công ${newRecords.length} hồ sơ!`);
    }
    setIsLoading(false);
  };

  const handleDelete = async (id: string) => {
    setIsLoading(true);
    const success = await deleteRecord(id);
    if (success) {
      await loadData();
    }
    setIsLoading(false);
  };

  const handleEdit = (record: HoSoDat) => {
    setEditingRecord(record);
    setView(ViewState.EDIT);
  };

  // NẾU CHƯA ĐĂNG NHẬP -> HIỆN LOGIN
  if (!currentUser) {
    return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  const NavItem = ({ icon: Icon, label, active, onClick }: { icon: any, label: string, active: boolean, onClick: () => void }) => (
    <button 
      onClick={onClick}
      className={`w-full flex items-center justify-between px-4 py-3 text-sm font-medium transition-all border-l-4 ${
        active 
          ? 'bg-blue-800 border-white text-white shadow-inner' 
          : 'border-transparent text-blue-100 hover:bg-blue-800 hover:text-white hover:border-blue-400'
      }`}
    >
      <div className="flex items-center gap-3">
        <Icon size={18} />
        <span>{label}</span>
      </div>
      {active && <ChevronRight size={16} />}
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gov-bg font-sans">
      {/* Loading Overlay */}
      {isLoading && (
        <div className="fixed inset-0 bg-black/20 z-50 flex items-center justify-center backdrop-blur-sm">
          <div className="bg-white p-4 rounded-lg shadow-lg flex items-center gap-3">
            <Loader2 className="animate-spin text-gov-primary" size={24} />
            <span className="text-gray-700 font-medium">Đang xử lý dữ liệu...</span>
          </div>
        </div>
      )}

      {/* Sidebar - Official Dark Blue */}
      <aside className="w-full md:w-64 bg-gov-primary text-white flex-shrink-0 flex flex-col shadow-xl z-20">
        <div className="h-16 flex items-center px-6 bg-blue-900 shadow-md">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1.5 rounded shadow">
              <Building2 className="text-gov-primary" size={20} />
            </div>
            <div>
              <h1 className="font-bold text-sm leading-tight uppercase tracking-wide">UBND P. Minh Hưng</h1>
              <p className="text-[10px] text-blue-200 font-light tracking-wider">HỆ THỐNG QUẢN LÝ ĐẤT ĐAI</p>
            </div>
          </div>
        </div>

        <div className="px-6 py-4">
          <div className="text-xs font-bold text-blue-300 uppercase mb-2 tracking-wider">Danh mục quản lý</div>
        </div>

        <nav className="flex-1 space-y-1">
          <NavItem 
            icon={LayoutDashboard} 
            label="Tổng Quan Báo Cáo" 
            active={view === ViewState.DASHBOARD} 
            onClick={() => setView(ViewState.DASHBOARD)} 
          />
          <NavItem 
            icon={List} 
            label="Danh sách hồ sơ" 
            active={view === ViewState.LIST} 
            onClick={() => setView(ViewState.LIST)} 
          />
          <NavItem 
            icon={PlusCircle} 
            label="Tiếp Nhận Hồ Sơ" 
            active={view === ViewState.ADD || view === ViewState.EDIT} 
            onClick={() => {
              setEditingRecord(undefined);
              setView(ViewState.ADD);
            }} 
          />

          {/* CHỈ ADMIN MỚI THẤY MENU NÀY */}
          {currentUser.role === 'ADMIN' && (
            <>
              <div className="px-6 py-4">
                <div className="text-xs font-bold text-blue-300 uppercase mb-2 tracking-wider">Hệ thống</div>
              </div>
              <NavItem 
                icon={Users} 
                label="Quản lý tài khoản" 
                active={view === ViewState.USERS} 
                onClick={() => setView(ViewState.USERS)} 
              />
            </>
          )}
        </nav>

        <div className="p-4 bg-blue-900 border-t border-blue-800">
          <div className="flex items-center gap-3">
            <div className="bg-blue-700 p-2 rounded-full">
               <UserCircle size={20} />
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-white truncate">{currentUser.fullName}</p>
              <p className="text-[10px] text-blue-300 truncate uppercase">{currentUser.role === 'ADMIN' ? 'Quản trị viên' : 'Cán bộ'}</p>
            </div>
            <button onClick={handleLogout} className="text-blue-300 hover:text-white" title="Đăng xuất">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-grow flex flex-col h-screen overflow-hidden">
        {/* Header Bar */}
        <header className="h-16 bg-white shadow-sm border-b flex items-center justify-between px-6 z-10 shrink-0">
          <div>
            <h2 className="text-lg font-bold text-gov-primary flex items-center gap-2">
              <span className="text-gray-400 font-normal">Hệ thống /</span> 
              {view === ViewState.DASHBOARD && 'Bảng Thống Kê Số Liệu'}
              {view === ViewState.LIST && 'Danh Sách Hồ Sơ Chuyển Mục Đích'}
              {(view === ViewState.ADD || view === ViewState.EDIT) && 'Xử Lý Hồ Sơ Chi Tiết'}
              {view === ViewState.USERS && 'Phân Quyền Hệ Thống'}
            </h2>
          </div>
          <div className="flex items-center gap-4 text-sm text-gray-600">
            <div className="text-right hidden md:block">
              <div className="font-medium">{new Date().toLocaleDateString('vi-VN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</div>
              <div className="text-xs text-gray-400">Phiên làm việc: #SESSION-2024</div>
            </div>
          </div>
        </header>

        {/* Content Scrollable Area */}
        <div className="flex-grow overflow-y-auto p-4 md:p-6 bg-gov-bg">
          <div className="max-w-7xl mx-auto space-y-6 pb-10">
            {view === ViewState.DASHBOARD && <Dashboard records={records} />}

            {view === ViewState.LIST && (
              <RecordList 
                records={records} 
                onEdit={handleEdit} 
                onDelete={handleDelete}
                onImport={handleImportRecords}
                userRole={currentUser.role} // Truyền role xuống để ẩn hiện nút
              />
            )}

            {(view === ViewState.ADD || view === ViewState.EDIT) && (
              <RecordForm 
                initialData={editingRecord} 
                onSave={handleSave} 
                onCancel={() => setView(ViewState.LIST)} 
              />
            )}

            {/* Chỉ hiện nếu là Admin */}
            {view === ViewState.USERS && currentUser.role === 'ADMIN' && (
              <UserManagement />
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef } from 'react';
import { HoSoDat, UserRole } from '../types';
import { Edit, Trash2, Search, FileDown, Upload, Filter, FileText, ScrollText } from 'lucide-react';
import { exportToCSV } from '../services/storage';
// @ts-ignore
import { read, utils } from 'xlsx';

interface Props {
  records: HoSoDat[];
  onEdit: (record: HoSoDat) => void;
  onDelete: (id: string) => void;
  onImport: (records: HoSoDat[]) => void;
  userRole?: UserRole; // Thêm prop role
}

const RecordList: React.FC<Props> = ({ records, onEdit, onDelete, onImport, userRole = 'USER' }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isAdmin = userRole === 'ADMIN';

  const filteredRecords = useMemo(() => {
    return records.filter(r => 
      r.chuSuDung.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.maHS.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.soGCN.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.diaChiThua.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [records, searchTerm]);

  const handleDelete = (id: string, name: string) => {
    if (window.confirm(`XÁC NHẬN XÓA HỒ SƠ?\n\nChủ sử dụng: ${name}\n\nHành động này không thể hoàn tác.`)) {
      onDelete(id);
    }
  };

  // Hàm tạo nội dung file Word (HTML giả lập)
  const exportToDoc = (filename: string, content: string) => {
    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>Export HTML to Word Document with JavaScript</title><style>body {font-family: 'Times New Roman', serif; font-size: 14pt;} p {margin: 0; padding: 0;} .center {text-align: center; font-weight: bold;} .bold {font-weight: bold;} .italic {font-style: italic;} .underline {text-decoration: underline;}</style></head><body>";
    const footer = "</body></html>";
    const sourceHTML = header + content + footer;

    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = `${filename}.doc`;
    fileDownload.click();
    document.body.removeChild(fileDownload);
  }

  const handleExportToTrinh = (r: HoSoDat) => {
    const content = `
      <div class='center'>
        <p>CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM</p>
        <p class='underline'>Độc lập - Tự do - Hạnh phúc</p>
        <br/>
        <p>TỜ TRÌNH</p>
        <p>Về việc đề nghị chuyển mục đích sử dụng đất</p>
      </div>
      <br/>
      <p>Kính gửi: UBND Thị xã Chơn Thành</p>
      <br/>
      <p>UBND Phường Minh Hưng tiếp nhận hồ sơ của ông/bà: <span class='bold'>${r.chuSuDung.toUpperCase()}</span></p>
      <p>Địa chỉ thường trú: ${r.diaChiChu}</p>
      <p>Căn cước công dân số: ${r.cccd}</p>
      <br/>
      <p>Đang sử dụng thửa đất số: <span class='bold'>${r.thua}</span>, Tờ bản đồ số: <span class='bold'>${r.to}</span></p>
      <p>Tại địa chỉ: ${r.diaChiThua}</p>
      <p>Giấy chứng nhận QSDĐ số: ${r.soGCN}, Cấp ngày: ${r.ngayCap}</p>
      <br/>
      <p>Tổng diện tích: ${r.dienTichTong} m2. Trong đó:</p>
      <p>- Diện tích đất ở hiện có: ${r.dienTichDatO} m2</p>
      <p>- Diện tích đất nông nghiệp: ${r.dienTichNN} m2</p>
      <br/>
      <p>Nay đề nghị xin chuyển mục đích sử dụng đất đối với thửa đất trên.</p>
      <p>Kính trình UBND thị xã xem xét giải quyết./.</p>
      <br/><br/>
      <div style='text-align: right'>
        <p class='italic'>Minh Hưng, ngày .... tháng .... năm 20...</p>
        <p class='bold'>CHỦ TỊCH</p>
        <br/><br/><br/>
        <p>(Đã ký)</p>
      </div>
    `;
    exportToDoc(`ToTrinh_${r.chuSuDung}`, content);
  };

  const handleExportQuyetDinh = (r: HoSoDat) => {
    const content = `
      <div class='center'>
        <p>ỦY BAN NHÂN DÂN</p>
        <p class='underline bold'>PHƯỜNG MINH HƯNG</p>
        <br/>
        <p>QUYẾT ĐỊNH</p>
        <p>Về việc xác nhận hồ sơ chuyển mục đích sử dụng đất</p>
      </div>
      <br/>
      <p>- Căn cứ Luật Đất đai năm 2013;</p>
      <p>- Căn cứ đơn xin chuyển mục đích sử dụng đất của ông/bà: <span class='bold'>${r.chuSuDung.toUpperCase()}</span></p>
      <br/>
      <div class='center'><p>QUYẾT ĐỊNH:</p></div>
      <br/>
      <p><span class='bold'>Điều 1.</span> Thống nhất đề nghị cho phép ông/bà ${r.chuSuDung} chuyển mục đích sử dụng đất tại thửa đất số ${r.thua}, tờ bản đồ số ${r.to}.</p>
      <p>Địa chỉ thửa đất: ${r.diaChiThua}</p>
      <p>Diện tích xin chuyển mục đích: ............... m2</p>
      <br/>
      <p><span class='bold'>Điều 2.</span> Công chức Địa chính - Xây dựng có trách nhiệm hướng dẫn công dân thực hiện nghĩa vụ tài chính theo quy định.</p>
      <br/>
      <p><span class='bold'>Điều 3.</span> Quyết định này có hiệu lực kể từ ngày ký./.</p>
      <br/><br/>
      <div style='text-align: right'>
        <p class='italic'>Minh Hưng, ngày .... tháng .... năm 20...</p>
        <p class='bold'>CHỦ TỊCH</p>
        <br/><br/><br/>
        <p>(Đã ký)</p>
      </div>
    `;
    exportToDoc(`QuyetDinh_${r.chuSuDung}`, content);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        // Sử dụng hàm read và utils được import trực tiếp
        const wb = read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        // Đọc dữ liệu thô từ Excel
        const data = utils.sheet_to_json(ws);

        // Map dữ liệu từ cột Excel (Tiếng Việt) sang Interface (Tiếng Anh)
        const mappedData: HoSoDat[] = data.map((row: any) => {
          const dtTong = Number(row['DT Tổng']) || 0;
          const dtO = Number(row['DT Đất ở']) || 0;

          return {
            id: crypto.randomUUID(),
            maHS: row['Mã HS']?.toString() || '',
            ngayNhanHS: row['Ngày nhận'] || new Date().toISOString().slice(0, 10),
            chuSuDung: row['Chủ sử dụng'] || 'Chưa xác định',
            diaChiChu: row['Địa chỉ chủ'] || '',
            mst: row['MST']?.toString() || '',
            cccd: row['CCCD']?.toString() || '',
            soGCN: row['Số GCN']?.toString() || '',
            ngayCap: row['Ngày cấp'] || '',
            thua: row['Thửa']?.toString() || '',
            to: row['Tờ']?.toString() || '',
            diaChiThua: row['Địa chỉ thửa'] || '',
            dienTichTong: dtTong,
            dienTichDatO: dtO,
            dienTichNN: Math.max(0, parseFloat((dtTong - dtO).toFixed(2))), // Tính lại NN để đảm bảo chính xác
            ghiChu: ''
          };
        }).filter((r: HoSoDat) => r.maHS !== '' && r.chuSuDung !== 'Chưa xác định'); // Lọc bỏ dòng trống

        if (mappedData.length > 0) {
          onImport(mappedData);
        } else {
          alert('Không tìm thấy dữ liệu hợp lệ trong file Excel.\nVui lòng kiểm tra lại tên cột.');
