const PriceList: React.FC<Props> = ({ userRole }) => {
  const [prices, setPrices] = useState<BangGiaDat[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<BangGiaDat | null>(null);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isAdmin = userRole === 'ADMIN';

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const data = await getPriceList();
    setPrices(data);
    setLoading(false);
  };

  const filteredPrices = useMemo(() => {
    return prices.filter(p => 
      p.tenDuong.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemDau?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemCuoi?.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [prices, searchTerm]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = utils.sheet_to_json(ws);

        // Map Excel headers to interface
        const mappedData: BangGiaDat[] = data.map((row: any) => ({
          tenDuong: row['Tên đường giao thông'] || row['Tên đường'] || '',
          diemDau: row['Điểm đầu'] || '',
          diemCuoi: row['Điểm cuối'] || '',
          giaDatO: Number(row['Giá đất ở']) || 0,
          giaTmDv: Number(row['Giá đất thương mại, dịch vụ']) || 0,
          giaSxPhiNn: Number(row['Giá đất cơ sở sản xuất phi nông nghiệp']) || Number(row['Giá SXKD']) || 0,
          namApDung: 2024
        })).filter((p: any) => p.tenDuong);

        if (mappedData.length > 0) {
          if(window.confirm(`Tìm thấy ${mappedData.length} dòng dữ liệu. Bạn có muốn nhập vào hệ thống?`)) {
             setLoading(true);
             await importPrices(mappedData);
             await loadData();
          }
        } else {
          alert("Không đọc được dữ liệu. Vui lòng kiểm tra tên cột trong file Excel.");
        }
      } catch (error) {
        console.error(error);
        alert("Lỗi đọc file Excel.");
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsBinaryString(file);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    await savePrice(isEditing);
    setIsEditing(null);
    loadData();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Xóa dòng giá này?")) {
      await deletePrice(id);
      loadData();
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('vi-VN').format(val);
  };

  return (
    <div className="space-y-4 fade-in h-full flex flex-col">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".xlsx,.xls" className="hidden" />

      {/* Toolbar */}
      <div className="bg-white p-4 rounded shadow-sm border border-gray-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2">
           <div className="bg-amber-600 text-white p-2 rounded">
             <Banknote size={18}/>
           </div>
           <div>
             <h3 className="font-bold text-gray-700 uppercase text-sm">Bảng Giá Đất 2024</h3>
             <p className="text-xs text-gray-500">Quyết định số 27/2024/QĐ-UBND</p>
           </div>
        </div>

        <div className="flex w-full md:w-auto gap-3">
          <div className="relative flex-grow md:flex-grow-0">
            <Search size={16} className="absolute left-3 top-2.5 text-gray-400" />
