import React, { useState, useEffect, useMemo, useRef } from 'react';
import { BangGiaDat, UserRole } from '../types';
import { getPriceList, savePrice, deletePrice, importPrices } from '../services/storage';
import { Search, Upload, Plus, Trash2, Edit2, Save, X, Banknote, RefreshCw, AlertTriangle } from 'lucide-react';
import * as XLSX from 'xlsx';

interface Props {
  userRole: UserRole;
}

const PriceList: React.FC<Props> = ({ userRole }) => {
  const [prices, setPrices] = useState<BangGiaDat[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<BangGiaDat | null>(null);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isAdmin = userRole === 'ADMIN';

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const data = await getPriceList();
    setPrices(data);
    setLoading(false);
  };

  const filteredPrices = useMemo(() => {
    return prices.filter(p => 
      p.tenDuong.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemDau?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemCuoi?.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [prices, searchTerm]);

  // Hàm chuyển đổi giá trị Excel (chuỗi có dấu chấm/phẩy) thành số chuẩn
  const parseExcelNumber = (val: any): number => {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    // Chuyển về chuỗi, xóa tất cả ký tự không phải số (giữ lại dấu chấm nếu là thập phân, nhưng giá đất thường là số nguyên)
    // Ở Việt Nam thường dùng dấu chấm (.) phân cách hàng nghìn -> Xóa hết dấu chấm
    const str = val.toString().replace(/\./g, '').replace(/,/g, '').replace(/\s/g, '');
    const num = Number(str);
    return isNaN(num) ? 0 : num;
  };

  // Hàm chuẩn hóa key từ Excel (xóa dấu tiếng Việt, viết thường, bỏ ký tự lạ) để so sánh
  const normalizeKey = (key: string) => {
    return key.toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // Bỏ dấu
      .replace(/[^a-z0-9]/g, ""); // Chỉ giữ lại chữ cái và số
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Đọc dữ liệu thô
        const rawData = XLSX.utils.sheet_to_json(ws);

        if (rawData.length === 0) {
           alert("File Excel trống!");
           return;
        }

        // Lấy danh sách các cột trong file Excel để kiểm tra (lấy dòng đầu tiên)
        const excelHeaders = Object.keys(rawData[0] as object);
        console.log("Các cột tìm thấy trong Excel:", excelHeaders);

        let countFoundKhoangSan = 0;

        const mappedData: BangGiaDat[] = rawData.map((row: any) => {
          let valSxPhiNn = 0;
          let valDatO = 0;
          let valTmDv = 0;
          let valTenDuong = '';
          let valDiemDau = '';
          let valDiemCuoi = '';

          // Duyệt qua từng cột trong dòng hiện tại để tìm dữ liệu
          Object.keys(row).forEach(originalKey => {
            const key = normalizeKey(originalKey); // Chuyển về dạng: "giadatcososanxuat..."

            // Logic nhận diện thông minh (Keyword matching)
            if (key.includes('tenduong')) valTenDuong = row[originalKey];
            else if (key.includes('diemdau')) valDiemDau = row[originalKey];
            else if (key.includes('diemcuoi')) valDiemCuoi = row[originalKey];

            // Nhận diện giá Đất Ở
            else if (key.includes('giadato') || (key.includes('gia') && key.includes('o') && !key.includes('phi'))) {
              valDatO = parseExcelNumber(row[originalKey]);
            }
            // Nhận diện giá TM-DV
            else if (key.includes('thuongmai') || key.includes('tmdv')) {
              valTmDv = parseExcelNumber(row[originalKey]);
            }
            // Nhận diện giá Khoáng sản / Phi nông nghiệp (ƯU TIÊN CAO)
            else if (
                key.includes('khoangsan') || 
                key.includes('phinongnghiep') || 
                (key.includes('sanxuat') && key.includes('phi')) ||
                key.includes('giasxkd')
            ) {
               valSxPhiNn = parseExcelNumber(row[originalKey]);
            }
          });

          if (valSxPhiNn > 0) countFoundKhoangSan++;

          return {
            id: crypto.randomUUID(),
            tenDuong: valTenDuong || '',
            diemDau: valDiemDau || '',
            diemCuoi: valDiemCuoi || '',
            giaDatO: valDatO,
            giaTmDv: valTmDv,
            giaSxPhiNn: valSxPhiNn, // Quan trọng: Đã qua xử lý parseExcelNumber
            namApDung: 2026
          };
        }).filter(p => p.tenDuong !== '');

        if (mappedData.length > 0) {
          let msg = `Tìm thấy ${mappedData.length} dòng dữ liệu bảng giá 2026.`;

          if (countFoundKhoangSan === 0) {
            msg += `\n\n⚠️ CẢNH BÁO: Không tìm thấy dữ liệu cột "Giá đất SX Phi Nông nghiệp & Khoáng sản" (Giá trị = 0).\n\nVui lòng kiểm tra lại tên cột trong Excel phải chứa từ "khoáng sản" hoặc "phi nông nghiệp".`;
          } else {
            msg += `\n\n✅ Đã đọc được cột "Khoáng sản/Phi nông nghiệp" ở ${countFoundKhoangSan} dòng.`;
          }

          if(window.confirm(`${msg}\n\nBạn có muốn nhập vào hệ thống?`)) {
             setLoading(true);
             const success = await importPrices(mappedData);
             if (success) {
               alert("Nhập dữ liệu thành công!");
             }
             await loadData();
          }
        } else {
          alert("Không đọc được dữ liệu. Vui lòng kiểm tra file Excel.");
        }
      } catch (error) {
        console.error(error);
        alert("Lỗi đọc file Excel: " + error);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsBinaryString(file);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    await savePrice(isEditing);
    setIsEditing(null);
    loadData();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Xóa dòng giá này?")) {
      await deletePrice(id);
      loadData();
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('vi-VN').format(val);
  };

  return (
    <div className="space-y-4 fade-in h-full flex flex-col">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".xlsx,.xls" className="hidden" />

      {/* Toolbar */}
      <div className="bg-white p-4 rounded shadow-sm border border-gray-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2">
           <div className="bg-amber-600 text-white p-2 rounded">
             <Banknote size={18}/>
           </div>
           <div>
             <h3 className="font-bold text-gray-700 uppercase text-sm">Bảng Giá Đất 2026</h3>
             <p className="text-xs text-gray-500">Áp dụng theo Quyết định mới nhất</p>
           </div>
        </div>

        <div className="flex w-full md:w-auto gap-3">
          <div className="relative flex-grow md:flex-grow-0">
            <Search size={16} className="absolute left-3 top-2.5 text-gray-400" />
            <input
              type="text"
              placeholder="Tìm tên đường..."
              className="pl-9 pr-4 py-2 border border-gray-300 rounded text-sm w-full md:w-64 focus:outline-none focus:ring-1 focus:ring-gov-primary"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <button 
            onClick={loadData} 
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 p-2 rounded border border-gray-300"
            title="Tải lại dữ liệu"
          >
            <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
          </button>

          {isAdmin && (
            <>
              <button 
                onClick={() => setIsEditing({ id: '', tenDuong: '', diemDau: '', diemCuoi: '', giaDatO: 0, giaTmDv: 0, giaSxPhiNn: 0, namApDung: 2026 } as BangGiaDat)}
                className="flex items-center gap-2 bg-gov-primary text-white px-3 py-2 rounded text-sm hover:bg-blue-800"
              >
                <Plus size={16} /> <span className="hidden sm:inline">Thêm mới</span>
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 bg-green-700 text-white px-3 py-2 rounded text-sm hover:bg-green-800"
              >
                <Upload size={16} /> <span className="hidden sm:inline">Nhập Excel</span>
              </button>
            </>
          )}
        </div>
      </div>

      {/* Edit Form Modal */}
      {isEditing && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl overflow-hidden animate-fade-in-down">
            <div className="bg-gov-primary px-6 py-4 flex justify-between items-center">
              <h3 className="text-white font-bold uppercase">{isEditing.id ? 'Cập nhật giá đất' : 'Thêm giá đất mới'}</h3>
              <button onClick={() => setIsEditing(null)} className="text-white hover:text-red-200"><X size={20}/></button>
            </div>
            <form onSubmit={handleSave} className="p-6 grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="md:col-span-2">
                <label className="block text-xs font-bold text-gray-700 mb-1">Tên đường giao thông</label>
                <input required className="w-full border rounded px-3 py-2 text-sm" value={isEditing.tenDuong} onChange={e => setIsEditing({...isEditing, tenDuong: e.target.value})} />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Điểm đầu</label>
                <input className="w-full border rounded px-3 py-2 text-sm" value={isEditing.diemDau} onChange={e => setIsEditing({...isEditing, diemDau: e.target.value})} />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Điểm cuối</label>
                <input className="w-full border rounded px-3 py-2 text-sm" value={isEditing.diemCuoi} onChange={e => setIsEditing({...isEditing, diemCuoi: e.target.value})} />
              </div>

              <div className="border-t md:col-span-2 my-2"></div>

              <div>
                <label className="block text-xs font-bold text-blue-800 mb-1">Giá đất ở (VNĐ)</label>
                <input type="number" className="w-full border border-blue-300 bg-blue-50 rounded px-3 py-2 text-sm font-bold text-right" value={isEditing.giaDatO} onChange={e => setIsEditing({...isEditing, giaDatO: Number(e.target.value)})} />
              </div>
              <div>
                <label className="block text-xs font-bold text-orange-800 mb-1">Giá TM-DV (VNĐ)</label>
                <input type="number" className="w-full border border-orange-300 bg-orange-50 rounded px-3 py-2 text-sm font-bold text-right" value={isEditing.giaTmDv} onChange={e => setIsEditing({...isEditing, giaTmDv: Number(e.target.value)})} />
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-bold text-purple-800 mb-1">Giá đất cơ sở sản xuất phi nông nghiệp và đất sử dụng cho hoạt động khoáng sản (VNĐ)</label>
                <input type="number" className="w-full border border-purple-300 bg-purple-50 rounded px-3 py-2 text-sm font-bold text-right" value={isEditing.giaSxPhiNn} onChange={e => setIsEditing({...isEditing, giaSxPhiNn: Number(e.target.value)})} />
              </div>

              <div className="md:col-span-2 flex justify-end gap-3 mt-4">
                <button type="button" onClick={() => setIsEditing(null)} className="px-4 py-2 border rounded text-gray-600 hover:bg-gray-50">Hủy</button>
                <button type="submit" className="px-4 py-2 bg-gov-primary text-white rounded hover:bg-blue-800 font-bold flex items-center gap-2"><Save size={16}/> Lưu lại</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Data Table */}
      <div className="bg-white rounded shadow-sm border border-gray-200 overflow-hidden flex-grow flex flex-col">
        <div className="overflow-auto flex-grow">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-100 sticky top-0 z-10">
              <tr>
                <th rowSpan={2} className="px-4 py-3 text-left text-xs font-bold text-gray-700 uppercase border-r border-b w-64">Tên đường</th>
                <th colSpan={2} className="px-4 py-2 text-center text-xs font-bold text-gray-700 uppercase border-b">Đoạn đường</th>
                <th colSpan={3} className="px-4 py-2 text-center text-xs font-bold text-gray-700 uppercase border-b">Giá đất (VNĐ/m²)</th>
                {isAdmin && <th rowSpan={2} className="px-4 py-3 text-center text-xs font-bold text-gray-700 border-l border-b w-20">Tác vụ</th>}
              </tr>
              <tr>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 border-b border-r bg-gray-50">Điểm đầu</th>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 border-b border-r bg-gray-50">Điểm cuối</th>
                <th className="px-4 py-2 text-right text-xs font-bold text-blue-800 border-b border-r bg-blue-50/50">Đất Ở</th>
                <th className="px-4 py-2 text-right text-xs font-bold text-orange-800 border-b border-r bg-orange-50/50">TM-DV</th>
                <th className="px-4 py-2 text-right text-xs font-bold text-purple-800 border-b bg-purple-50/50" title="Giá đất cơ sở sản xuất phi nông nghiệp và đất sử dụng cho hoạt động khoáng sản">
                  SX Phi NN & Khoáng sản
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 bg-white">
              {loading ? (
                 <tr><td colSpan={7} className="text-center py-10 text-gray-500">Đang tải dữ liệu...</td></tr>
              ) : filteredPrices.length === 0 ? (
                 <tr><td colSpan={7} className="text-center py-10 text-gray-500 italic">Không tìm thấy dữ liệu giá đất</td></tr>
              ) : (
                filteredPrices.map((p, idx) => (
                  <tr key={p.id || idx} className="hover:bg-gray-50">
                    <td className="px-4 py-3 text-sm font-bold text-gray-800 border-r">{p.tenDuong}</td>
                    <td className="px-4 py-3 text-sm text-gray-600 border-r">{p.diemDau}</td>
                    <td className="px-4 py-3 text-sm text-gray-600 border-r">{p.diemCuoi}</td>
                    <td className="px-4 py-3 text-sm text-right font-bold text-blue-700 border-r bg-blue-50/30">{formatCurrency(p.giaDatO)}</td>
                    <td className="px-4 py-3 text-sm text-right font-medium text-orange-700 border-r bg-orange-50/30">{formatCurrency(p.giaTmDv)}</td>
                    <td className="px-4 py-3 text-sm text-right font-medium text-purple-700 bg-purple-50/30">{formatCurrency(p.giaSxPhiNn)}</td>
                    {isAdmin && (
                      <td className="px-4 py-3 text-center border-l">
                         <div className="flex justify-center gap-2">
                           <button onClick={() => setIsEditing(p)} className="text-blue-600 hover:text-blue-800"><Edit2 size={16}/></button>
                           <button onClick={() => handleDelete(p.id)} className="text-red-600 hover:text-red-800"><Trash2 size={16}/></button>
                         </div>
                      </td>
                    )}
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default PriceList;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { BangGiaDat, UserRole } from '../types';
import { getPriceList, savePrice, deletePrice, importPrices } from '../services/storage';
import { Search, Upload, Plus, Trash2, Edit2, Save, X, Banknote, RefreshCw } from 'lucide-react';
import * as XLSX from 'xlsx';

interface Props {
  userRole: UserRole;
}

const PriceList: React.FC<Props> = ({ userRole }) => {
  const [prices, setPrices] = useState<BangGiaDat[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<BangGiaDat | null>(null);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isAdmin = userRole === 'ADMIN';

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const data = await getPriceList();
    setPrices(data);
    setLoading(false);
  };

  const filteredPrices = useMemo(() => {
    return prices.filter(p => 
      p.tenDuong.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemDau?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemCuoi?.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [prices, searchTerm]);

  const parseExcelNumber = (val: any): number => {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    const str = val.toString().replace(/\./g, '').replace(/,/g, '').replace(/\s/g, '');
    const num = Number(str);
    return isNaN(num) ? 0 : num;
  };

  // Hàm chuẩn hóa key: bỏ dấu, bỏ khoảng trắng, chữ thường
  const normalizeKey = (key: string) => {
    return key.toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]/g, "");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawData = XLSX.utils.sheet_to_json(ws);

        if (rawData.length === 0) {
           alert("File Excel trống!");
           return;
        }

        // --- DEBUG LOGIC ---
        // Lấy dòng đầu tiên để kiểm tra code nhận diện được cột nào
        const firstRow = rawData[0] as any;
        const headers = Object.keys(firstRow);
        console.log("Các cột tìm thấy:", headers);
        // -------------------

        let countFoundKhoangSan = 0;

        const mappedData: BangGiaDat[] = rawData.map((row: any) => {
          let valSxPhiNn = 0;
          let valDatO = 0;
          let valTmDv = 0;
          let valTenDuong = '';
          let valDiemDau = '';
          let valDiemCuoi = '';

          Object.keys(row).forEach(originalKey => {
            const key = normalizeKey(originalKey); 
            // key lúc này sẽ dạng: "phinongnghiep", "giadat", "diemdau"...

            // 1. Tên đường
            if (key.includes('tenduong')) valTenDuong = row[originalKey];

            // 2. Điểm đầu/cuối
            else if (key.includes('diemdau')) valDiemDau = row[originalKey];
            else if (key.includes('diemcuoi')) valDiemCuoi = row[originalKey];

            // 3. Giá Đất Ở
            else if (key.includes('giadato') || (key.includes('gia') && key.includes('o') && !key.includes('phi'))) {
              valDatO = parseExcelNumber(row[originalKey]);
            }

            // 4. Giá TM-DV
            else if (key.includes('thuongmai') || key.includes('tmdv')) {
              valTmDv = parseExcelNumber(row[originalKey]);
            }

            // 5. Giá Phi Nông Nghiệp (Quan trọng nhất)
            // Logic: Chấp nhận từ khóa "phi nông", "khoáng sản", "sản xuất"
            else if (
                key.includes('phinong') || 
                key.includes('khoangsan') || 
                key.includes('sanxuat')
            ) {
               valSxPhiNn = parseExcelNumber(row[originalKey]);
            }
          });

          if (valSxPhiNn > 0) countFoundKhoangSan++;

          return {
            id: crypto.randomUUID(),
            tenDuong: valTenDuong || '',
            diemDau: valDiemDau || '',
            diemCuoi: valDiemCuoi || '',
            giaDatO: valDatO,
            giaTmDv: valTmDv,
            giaSxPhiNn: valSxPhiNn, 
            namApDung: 2026
          };
        }).filter(p => p.tenDuong !== '');

        if (mappedData.length > 0) {
          // Thông báo chi tiết cho người dùng biết kết quả đọc
          let msg = `Đã đọc ${mappedData.length} dòng dữ liệu.\n`;

          if (countFoundKhoangSan === 0) {
            msg += `\n⚠️ CẢNH BÁO: Cột "Phi nông nghiệp" đang bị nhận diện là 0 hoặc không tìm thấy.\n`;
            msg += `(Phần mềm đang tìm cột có chứa chữ: "phi nông", "khoáng sản", hoặc "sản xuất")\n`;
            msg += `\nCác cột trong file của bạn là:\n- ${headers.join('\n- ')}`;
          } else {
            msg += `\n✅ Đã nhận diện được giá "Phi nông nghiệp" ở ${countFoundKhoangSan} dòng.`;
          }

          if(window.confirm(`${msg}\n\nBạn có muốn lưu vào Database không?`)) {
             setLoading(true);
             const success = await importPrices(mappedData);
             if (success) {
               alert("Đã lưu thành công!");
               await loadData();
             } else {
               alert("Lỗi khi lưu vào Database! Vui lòng kiểm tra lại cấu trúc bảng trong Supabase.");
             }
             setLoading(false);
          }
        } else {
          alert("Không tìm thấy dữ liệu hợp lệ trong file Excel.");
        }
      } catch (error) {
        console.error(error);
        alert("Lỗi đọc file Excel: " + error);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsBinaryString(file);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    await savePrice(isEditing);
    setIsEditing(null);
    loadData();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Xóa dòng giá này?")) {
      await deletePrice(id);
      loadData();
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('vi-VN').format(val);
  };

  return (
    <div className="space-y-4 fade-in h-full flex flex-col">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".xlsx,.xls" className="hidden" />

      {/* Toolbar */}
      <div className="bg-white p-4 rounded shadow-sm border border-gray-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2">
           <div className="bg-amber-600 text-white p-2 rounded">
             <Banknote size={18}/>
           </div>
           <div>
             <h3 className="font-bold text-gray-700 uppercase text-sm">Bảng Giá Đất 2026</h3>
             <p className="text-xs text-gray-500">Áp dụng theo Quyết định mới nhất</p>
           </div>
        </div>

        <div className="flex w-full md:w-auto gap-3">
          <div className="relative flex-grow md:flex-grow-0">
            <Search size={16} className="absolute left-3 top-2.5 text-gray-400" />
            <input
              type="text"
              placeholder="Tìm tên đường..."
              className="pl-9 pr-4 py-2 border border-gray-300 rounded text-sm w-full md:w-64 focus:outline-none focus:ring-1 focus:ring-gov-primary"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <button 
            onClick={loadData} 
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 p-2 rounded border border-gray-300"
            title="Tải lại dữ liệu"
          >
            <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
          </button>

          {isAdmin && (
            <>
              <button 
                onClick={() => setIsEditing({ id: '', tenDuong: '', diemDau: '', diemCuoi: '', giaDatO: 0, giaTmDv: 0, giaSxPhiNn: 0, namApDung: 2026 } as BangGiaDat)}
                className="flex items-center gap-2 bg-gov-primary text-white px-3 py-2 rounded text-sm hover:bg-blue-800"
              >
                <Plus size={16} /> <span className="hidden sm:inline">Thêm mới</span>
              </button>
              <button 
