import React, { useState, useEffect, useMemo, useRef } from 'react';
import { BangGiaDat, UserRole } from '../types';
import { getPriceList, savePrice, deletePrice, importPrices } from '../services/storage';
import { Search, Upload, Plus, Trash2, Edit2, Save, X, Banknote, RefreshCw } from 'lucide-react';
import * as XLSX from 'xlsx';

interface Props {
  userRole: UserRole;
}

const PriceList: React.FC<Props> = ({ userRole }) => {
  const [prices, setPrices] = useState<BangGiaDat[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<BangGiaDat | null>(null);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isAdmin = userRole === 'ADMIN';

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const data = await getPriceList();
    setPrices(data);
    setLoading(false);
  };

  const filteredPrices = useMemo(() => {
    return prices.filter(p => 
      p.tenDuong.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemDau?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.diemCuoi?.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [prices, searchTerm]);

  const parseExcelNumber = (val: any): number => {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    // Xóa dấu chấm, phẩy, khoảng trắng, chữ VNĐ...
    const str = val.toString().replace(/[^0-9]/g, ''); 
    const num = Number(str);
    return isNaN(num) ? 0 : num;
  };

  // Hàm chuẩn hóa key: bỏ dấu, bỏ khoảng trắng, chữ thường
  const normalizeKey = (key: string) => {
    return key.toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]/g, "");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Đọc dữ liệu thô, header: 1 nghĩa là lấy mảng mảng dữ liệu thô để tự xử lý header
        const rawData = XLSX.utils.sheet_to_json(ws);

        if (rawData.length === 0) {
           alert("File Excel trống!");
           return;
        }

        // --- DEBUG LOGIC ---
        const firstRow = rawData[0] as any;
        const headers = Object.keys(firstRow);
        console.log("Các cột tìm thấy trong Excel:", headers);
        // -------------------

        let countFoundKhoangSan = 0;

        const mappedData: BangGiaDat[] = rawData.map((row: any) => {
          let valSxPhiNn = 0;
          let valDatO = 0;
          let valTmDv = 0;
          let valTenDuong = '';
          let valDiemDau = '';
          let valDiemCuoi = '';

          Object.keys(row).forEach(originalKey => {
            const key = normalizeKey(originalKey); 
            // key normalized: "giasxkdphinn", "giadat", "diemdau"...

            // 1. Tên đường
            if (key.includes('tenduong') || key === 'duong') valTenDuong = row[originalKey];

            // 2. Điểm đầu/cuối
            else if (key.includes('diemdau') || key === 'tu') valDiemDau = row[originalKey];
            else if (key.includes('diemcuoi') || key === 'den') valDiemCuoi = row[originalKey];

            // 3. Giá Đất Ở (Ưu tiên check kỹ để tránh nhầm với Phi NN)
            else if (
              (key.includes('giadato') || (key.includes('o') && key.includes('dat'))) && 
              !key.includes('phi') && !key.includes('sx')
            ) {
              valDatO = parseExcelNumber(row[originalKey]);
            }

            // 4. Giá TM-DV
            else if (key.includes('thuongmai') || key.includes('tmdv')) {
              valTmDv = parseExcelNumber(row[originalKey]);
            }

            // 5. Giá Phi Nông Nghiệp / Khoáng Sản / SXKD (Logic Mới)
            else if (
                key.includes('phinong') ||   // "phi nông nghiệp"
                key.includes('khoangsan') || // "khoáng sản"
                key.includes('sanxuat') ||   // "sản xuất"
                key.includes('sxkd') ||      // "sxkd"
                key.includes('phinn') ||     // "phi nn"
                (key.includes('phi') && key.includes('nn')) // Chứa cả "phi" và "nn"
            ) {
               valSxPhiNn = parseExcelNumber(row[originalKey]);
            }
          });

          if (valSxPhiNn > 0) countFoundKhoangSan++;

          return {
            id: crypto.randomUUID(),
            tenDuong: valTenDuong || '',
            diemDau: valDiemDau || '',
            diemCuoi: valDiemCuoi || '',
            giaDatO: valDatO,
            giaTmDv: valTmDv,
            giaSxPhiNn: valSxPhiNn, 
            namApDung: 2026
          };
        }).filter(p => p.tenDuong !== ''); // Lọc bỏ dòng không có tên đường

        if (mappedData.length > 0) {
          let msg = `Đã đọc ${mappedData.length} dòng dữ liệu.\n`;

          if (countFoundKhoangSan === 0) {
            msg += `\n⚠️ CẢNH BÁO QUAN TRỌNG:\nKhông đọc được cột "SXKD/Phi Nông Nghiệp" (Tất cả giá trị = 0).\n`;
            msg += `\nHệ thống đã thử tìm các từ khóa: "sxkd", "phi nn", "khoáng sản", "phi nông"... nhưng không thấy.\n`;
            msg += `\nCác cột trong file của bạn: [ ${headers.join(', ')} ]`;
          } else {
            msg += `\n✅ Đã nhận diện giá "SXKD Phi NN" ở ${countFoundKhoangSan} dòng.`;
          }

          if(window.confirm(`${msg}\n\nBạn có muốn lưu vào Database không?`)) {
             setLoading(true);
             const success = await importPrices(mappedData);
             if (success) {
               alert("Đã lưu thành công!");
               await loadData();
             } else {
               alert("Lỗi lưu Database! Hãy kiểm tra lại tên cột trong Supabase (giaSxPhiNn).");
             }
             setLoading(false);
          }
        } else {
          alert("Không tìm thấy dữ liệu hợp lệ (Cột Tên đường bị thiếu?)");
        }
      } catch (error) {
        console.error(error);
        alert("Lỗi đọc file Excel: " + error);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsBinaryString(file);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    await savePrice(isEditing);
    setIsEditing(null);
    loadData();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Xóa dòng giá này?")) {
      await deletePrice(id);
      loadData();
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('vi-VN').format(val);
  };

  return (
    <div className="space-y-4 fade-in h-full flex flex-col">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".xlsx,.xls" className="hidden" />

      {/* Toolbar */}
      <div className="bg-white p-4 rounded shadow-sm border border-gray-200 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2">
           <div className="bg-amber-600 text-white p-2 rounded">
             <Banknote size={18}/>
           </div>
           <div>
             <h3 className="font-bold text-gray-700 uppercase text-sm">Bảng Giá Đất 2026</h3>
             <p className="text-xs text-gray-500">Áp dụng theo Quyết định mới nhất</p>
           </div>
        </div>

        <div className="flex w-full md:w-auto gap-3">
          <div className="relative flex-grow md:flex-grow-0">
            <Search size={16} className="absolute left-3 top-2.5 text-gray-400" />
            <input
              type="text"
              placeholder="Tìm tên đường..."
              className="pl-9 pr-4 py-2 border border-gray-300 rounded text-sm w-full md:w-64 focus:outline-none focus:ring-1 focus:ring-gov-primary"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <button 
            onClick={loadData} 
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 p-2 rounded border border-gray-300"
            title="Tải lại dữ liệu"
          >
            <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
          </button>

          {isAdmin && (
            <>
              <button 
                onClick={() => setIsEditing({ id: '', tenDuong: '', diemDau: '', diemCuoi: '', giaDatO: 0, giaTmDv: 0, giaSxPhiNn: 0, namApDung: 2026 } as BangGiaDat)}
                className="flex items-center gap-2 bg-gov-primary text-white px-3 py-2 rounded text-sm hover:bg-blue-800"
              >
                <Plus size={16} /> <span className="hidden sm:inline">Thêm mới</span>
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 bg-green-700 text-white px-3 py-2 rounded text-sm hover:bg-green-800"
              >
                <Upload size={16} /> <span className="hidden sm:inline">Nhập Excel</span>
              </button>
            </>
          )}
        </div>
      </div>

      {/* Edit Form Modal */}
      {isEditing && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl overflow-hidden animate-fade-in-down">
            <div className="bg-gov-primary px-6 py-4 flex justify-between items-center">
              <h3 className="text-white font-bold uppercase">{isEditing.id ? 'Cập nhật giá đất' : 'Thêm giá đất mới'}</h3>
              <button onClick={() => setIsEditing(null)} className="text-white hover:text-red-200"><X size={20}/></button>
            </div>
            <form onSubmit={handleSave} className="p-6 grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="md:col-span-2">
                <label className="block text-xs font-bold text-gray-700 mb-1">Tên đường giao thông</label>
                <input required className="w-full border rounded px-3 py-2 text-sm" value={isEditing.tenDuong} onChange={e => setIsEditing({...isEditing, tenDuong: e.target.value})} />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Điểm đầu</label>
                <input className="w-full border rounded px-3 py-2 text-sm" value={isEditing.diemDau} onChange={e => setIsEditing({...isEditing, diemDau: e.target.value})} />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Điểm cuối</label>
                <input className="w-full border rounded px-3 py-2 text-sm" value={isEditing.diemCuoi} onChange={e => setIsEditing({...isEditing, diemCuoi: e.target.value})} />
              </div>

              <div className="border-t md:col-span-2 my-2"></div>

              <div>
                <label className="block text-xs font-bold text-blue-800 mb-1">Giá đất ở (VNĐ)</label>
                <input type="number" className="w-full border border-blue-300 bg-blue-50 rounded px-3 py-2 text-sm font-bold text-right" value={isEditing.giaDatO} onChange={e => setIsEditing({...isEditing, giaDatO: Number(e.target.value)})} />
              </div>
              <div>
                <label className="block text-xs font-bold text-orange-800 mb-1">Giá TM-DV (VNĐ)</label>
                <input type="number" className="w-full border border-orange-300 bg-orange-50 rounded px-3 py-2 text-sm font-bold text-right" value={isEditing.giaTmDv} onChange={e => setIsEditing({...isEditing, giaTmDv: Number(e.target.value)})} />
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-bold text-purple-800 mb-1">Giá đất SX Phi Nông nghiệp & Khoáng sản (VNĐ)</label>
                <input type="number" className="w-full border border-purple-300 bg-purple-50 rounded px-3 py-2 text-sm font-bold text-right" value={isEditing.giaSxPhiNn} onChange={e => setIsEditing({...isEditing, giaSxPhiNn: Number(e.target.value)})} />
              </div>

              <div className="md:col-span-2 flex justify-end gap-3 mt-4">
                <button type="button" onClick={() => setIsEditing(null)} className="px-4 py-2 border rounded text-gray-600 hover:bg-gray-50">Hủy</button>
                <button type="submit" className="px-4 py-2 bg-gov-primary text-white rounded hover:bg-blue-800 font-bold flex items-center gap-2"><Save size={16}/> Lưu lại</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Data Table */}
      <div className="bg-white rounded shadow-sm border border-gray-200 overflow-hidden flex-grow flex flex-col">
        <div className="overflow-auto flex-grow">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-100 sticky top-0 z-10">
